// 在 DWG 中，文本通常以 TTF 或 SHX 字体形式存储
// 对于中文字符，如果是 SHX 字体，文本可能以特定的编码存储

// 尝试搜索一些常见的 DWG 文本标记
// AutoCAD 文本对象通常以特定标记开头
// 搜索 "TEXT" 或 "MTEXT" 等标记
const markers = ['TEXT', 'MTEXT', 'Text', 'MText', 'AcDbText', 'AcDbMText'];
for (const marker of markers) {
  const buf = Buffer.from(marker, 'ascii');
  let pos = 0;
  let count = 0;
  while ((pos = buffer.indexOf(buf, pos)) !== -1) {
    count++;
    pos += buf.length;
  }
  if (count > 0) {
    console.log(`"${marker}": ${count} 处`);
  }
}

// 搜索 DWG 句柄编码模式（通常文本对象附近会有句柄信息）
// 搜索可能的中文文本区域 - 寻找连续的 ASCII 可打印字符序列
console.log('\n=== 搜索可读文本区域 ===');
let i = 0;
const textChunks = [];
while (i < buffer.length) {
  // 跳过非文本区域
  if (buffer[i] >= 0x20 && buffer[i] <= 0x7E) {
    let start = i;
    while (i < buffer.length && buffer[i] >= 0x20 && buffer[i] <= 0x7E) {
      i++;
    }
    const chunk = buffer.slice(start, i).toString('ascii');
    if (chunk.length > 4) {
      textChunks.push({ pos: start, text: chunk });
    }
  } else {
    i++;
  }
}

// 过滤出有意义的文本
console.log(`找到 ${textChunks.length} 个 ASCII 文本块`);
const meaningful = textChunks.filter(t => 
  t.text.includes('TABLE') || t.text.includes('BLOCK') || 
  t.text.includes('LAYER') || t.text.includes('STYLE') ||
  t.text.includes('DIMENSION') || t.text.includes('VIEW') ||
  t.text.includes('VPORT') || t.text.includes('APPID')
);

for (const t of meaningful.slice(0, 30)) {
