    if ((code >= 0x4E00 && code <= 0x9FFF) || 
        (code >= 0x3400 && code <= 0x4DBF) ||
        (code >= 0xF900 && code <= 0xFAFF) ||
        (code >= 0x2F800 && code <= 0x2FA1F)) {
      // 找到了中文字符，尝试提取一段连续的文本
      let start = Math.max(0, i - 20);
      let end = Math.min(buffer.length, i + 60);
      let chunk = buffer.slice(start, end);

      // 尝试解码为 UTF-16LE
      try {
        let text = '';
        for (let j = 0; j < chunk.length; j += 2) {
          if (j + 1 < chunk.length) {
            const c = chunk[j] | (chunk[j+1] << 8);
            if (c >= 0x20 && c <= 0xFFFF) {
              text += String.fromCharCode(c);
            } else {
              text += '?';
            }
          }
        }
        // 过滤出包含有意义中文的文本
        if (/[\u4e00-\u9fff\u3400-\u4dbf]/.test(text) && text.length > 4) {
          textBlocks.push({ pos: start, text });
